#include <stdio.h>
#include "riscv_nn_convolution.h"
#include "test_util.h"
#ifdef PF_COUNTER
#include "nds_pfcounter.h"
#endif

int test(char* fname_src1,
         char* fname_src2,
         char* fname_bias,
         char* fname_golden,
         uint16_t in_tensor_dim,
         uint16_t in_tensor_ch,
         uint16_t out_tensor_ch,
         uint16_t ker_dim,
         uint16_t pad,
         uint16_t stride,
         uint16_t pre_rshift,
         uint16_t out_scale,
         uint16_t post_rshift,
         uint16_t out_tensor_dim)
{
    {
        dump_param("in_tensor_dim=%" PRIu16 ";in_tensor_ch=%" PRIu16
            ";out_tensor_ch=%" PRIu16 ";ker_dim=%" PRIu16 ";pad=%" PRIu16
            ";stride_=%" PRIu16 ";pre_rshift=%" PRIu16 ";out_scale=%#" PRIx16
            ";post_rshift=%" PRIu16 ";out_tensor_dim=%" PRIu16 , in_tensor_dim,
            in_tensor_ch, out_tensor_ch, ker_dim, pad, stride, pre_rshift,
            out_scale, post_rshift, out_tensor_dim);
    }

    uint32_t src1_len = (uint32_t)in_tensor_ch * in_tensor_dim * in_tensor_dim;
    uint32_t src2_len = (uint32_t)out_tensor_ch * in_tensor_ch * ker_dim * ker_dim;
    uint32_t buf_len = riscv_nn_conv_sym_get_buffer_size(in_tensor_dim, in_tensor_dim, in_tensor_ch, out_tensor_ch, ker_dim, ker_dim, pad, pad, stride, stride, out_tensor_dim, out_tensor_dim);
    // uint32_t buf_len  = (uint32_t)in_tensor_ch * ker_dim * ker_dim * 2;
    uint32_t out_len  = (uint32_t)out_tensor_ch * out_tensor_dim * out_tensor_dim;

    FILE *fptr_src1, *fptr_src2, *fptr_bias, *fptr_golden;
    //backup originally malloced starting address for later memory releasing
    void *src1_ori, *src2_ori, *out_ori, *in_tmp_buf_ori, *bias_ori, *golden_ori;

    q7_t *src1 = (q7_t*)test_malloc(sizeof(q7_t) * src1_len, "src1", &src1_ori);
    q7_t *src2 = (q7_t*)test_malloc(sizeof(q7_t) * src2_len, "src2", &src2_ori);
    q7_t *out = (q7_t*)test_malloc(sizeof(q7_t) * out_len, "out", &out_ori);
    q15_t *in_tmp_buf = (q15_t*)test_malloc(buf_len, "in_tmp_buf", &in_tmp_buf_ori);
    q31_t *bias = (q31_t*)test_malloc(sizeof(q31_t) * out_tensor_ch, "bias", &bias_ori);
    q7_t *golden = (q7_t*)test_malloc(sizeof(q7_t) * out_len, "golden", &golden_ori);

    test_Fopen(fname_src1, "rb", &fptr_src1);
    test_Fopen(fname_src2, "rb", &fptr_src2);
    test_Fopen(fname_bias, "rb", &fptr_bias);
    test_Fread(src1, sizeof(*src1), src1_len, fptr_src1, "src1");
    test_Fread(src2, sizeof(*src2), src2_len, fptr_src2, "src2");
    test_Fread(bias, sizeof(*bias), out_tensor_ch, fptr_bias, "bias");
    process_after_reading_input_data();

#ifdef ENA_RUN_TWICE
    riscv_nn_conv_HWC_s8_s8_s8_sym_bias_fast(src1, in_tensor_dim, in_tensor_ch, src2, out_tensor_ch, ker_dim, pad, stride, bias, pre_rshift, out_scale, post_rshift, out, out_tensor_dim, in_tmp_buf);
#endif

    process_before_perf_measuring();
#ifdef PF_COUNTER
    startPFM;
#endif
    riscv_nn_conv_HWC_s8_s8_s8_sym_bias_fast(src1, in_tensor_dim, in_tensor_ch, src2, out_tensor_ch, ker_dim, pad, stride, bias, pre_rshift, out_scale, post_rshift, out, out_tensor_dim, in_tmp_buf);
#ifdef PF_COUNTER
    stopPFM;
    readResult();
#endif

#if ENA_DUMP_GOLDEN
    test_Fopen(fname_golden, "wb+", &fptr_golden);
    fwrite(out, sizeof(*golden), out_len, fptr_golden);
    uint32_t retStatus = NDS_SUCCESS;
#else
    test_Fopen(fname_golden, "rb", &fptr_golden);
    test_Fread(golden, sizeof(*golden), out_len, fptr_golden, "golden");
    uint32_t retStatus = verify_buffer(out, golden, out_len, sizeof(*out), 0);
#endif

    test_free(&src1_ori);
    test_free(&src2_ori);
    test_free(&out_ori);
    test_free(&in_tmp_buf_ori);
    test_free(&bias_ori);
    test_free(&golden_ori);
    fclose(fptr_src1);
    fclose(fptr_src2);
    fclose(fptr_bias);
    fclose(fptr_golden);

    return retStatus;
}

int main (void)
{
    enable_fs_and_vs();
    uint16_t in_tensor_dim, in_tensor_ch, out_tensor_ch, ker_dim, pad,
    stride, pre_rshift, out_scale, post_rshift, out_tensor_dim;
    uint32_t retStatus=NDS_SUCCESS;
